scripts.script:
// A wandering line (numeric x, ~45 points) so there is room to zoom, pan,
// annotate and measure. Randomize regenerates it into a fresh checkpoint.
function randomSeries() {
  var d = []
  var v = 45 + Math.random() * 25
  for (var i = 0; i < 45; i++) {
    v += (Math.random() - 0.5) * 22
    if (v < 8) v = 8
    if (v > 100) v = 100
    d.push([i + 1, Math.round(v)])
  }
  return d
}

html:
Undo Redo Randomize data Clear history history: empty
{{ charts[0] }}
History is enabled with chart: { history: { enabled: true } }. Every data update, zoom, pan, annotation and measurement commits a checkpoint. Right-click the plot to add a note, drop a dashed marker line, or start a measurement (context menu); drag-select or use the toolbar to zoom and pan; hold m and drag to measure; press Randomize to replace the data. Then step back with Undo / Redo (or press Cmd/Ctrl + Z and Shift + Cmd/Ctrl + Z). The buttons enable from the historyChange event via chart.history.state().

vanilla-js-script:
var undoBtn = document.getElementById('undo')
var redoBtn = document.getElementById('redo')
var readout = document.getElementById('readout')

function syncButtons(state) {
  if (!state) state = chart.history.state()
  undoBtn.disabled = !state.canUndo
  redoBtn.disabled = !state.canRedo
  readout.innerHTML =
    'history: ' + (state.index + 1) + ' / ' + state.length + ' checkpoints'
}

chart.addEventListener('historyChange', function (c, state) {
  syncButtons(state && state.length != null ? state : undefined)
})

undoBtn.addEventListener('click', function () { chart.history.undo() })
redoBtn.addEventListener('click', function () { chart.history.redo() })
document.getElementById('randomize').addEventListener('click', function () {
  chart.updateSeries([{ name: 'Value', data: randomSeries() }])
})
document.getElementById('reset').addEventListener('click', function () {
  chart.history.clear()
})

// initial state once the baseline checkpoint lands
setTimeout(syncButtons, 300)

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id, then wire the same buttons the vanilla build does.
  // (randomSeries lives in the shared head script.) History drives the chart
  // instance directly, so no React state changes and the chart is never
  // re-rendered under it.
  let chart
  const timer = window.setInterval(() => {
    chart = ApexCharts.getChartByID('rewind-demo')
    if (!chart) return
    window.clearInterval(timer)

    const undoBtn = document.getElementById('undo')
    const redoBtn = document.getElementById('redo')
    const readout = document.getElementById('readout')

    function syncButtons(state) {
      if (!state) state = chart.history.state()
      undoBtn.disabled = !state.canUndo
      redoBtn.disabled = !state.canRedo
      readout.innerHTML =
        'history: ' + (state.index + 1) + ' / ' + state.length + ' checkpoints'
    }

    chart.addEventListener('historyChange', function (c, state) {
      syncButtons(state && state.length != null ? state : undefined)
    })

    undoBtn.addEventListener('click', function () { chart.history.undo() })
    redoBtn.addEventListener('click', function () { chart.history.redo() })
    document.getElementById('randomize').addEventListener('click', function () {
      chart.updateSeries([{ name: 'Value', data: randomSeries() }])
    })
    document.getElementById('reset').addEventListener('click', function () {
      chart.history.clear()
    })

    // initial state once the baseline checkpoint lands
    window.setTimeout(syncButtons, 300)
  }, 50)

  return () => {
    window.clearInterval(timer)
  }
}, [])

vue-script:
mounted: function () {
  // The vue-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id, then wire the same buttons the vanilla build does.
  // (randomSeries lives in the shared head script.)
  var me = this
  me.rewindTimer = window.setInterval(function () {
    var chart = ApexCharts.getChartByID('rewind-demo')
    if (!chart) return
    window.clearInterval(me.rewindTimer)

    var undoBtn = document.getElementById('undo')
    var redoBtn = document.getElementById('redo')
    var readout = document.getElementById('readout')

    function syncButtons(state) {
      if (!state) state = chart.history.state()
      undoBtn.disabled = !state.canUndo
      redoBtn.disabled = !state.canRedo
      readout.innerHTML =
        'history: ' + (state.index + 1) + ' / ' + state.length + ' checkpoints'
    }

    chart.addEventListener('historyChange', function (c, state) {
      syncButtons(state && state.length != null ? state : undefined)
    })

    undoBtn.addEventListener('click', function () { chart.history.undo() })
    redoBtn.addEventListener('click', function () { chart.history.redo() })
    document.getElementById('randomize').addEventListener('click', function () {
      chart.updateSeries([{ name: 'Value', data: randomSeries() }])
    })
    document.getElementById('reset').addEventListener('click', function () {
      chart.history.clear()
    })

    // initial state once the baseline checkpoint lands
    window.setTimeout(syncButtons, 300)
  }, 50)
},
beforeDestroy: function () {
  if (this.rewindTimer) window.clearInterval(this.rewindTimer)
},
